def test_app_launch():
    driver.launch_app()
    assert driver.find_element('id', 'home_screen').is_displayed()

def test_accessibility_labels():
    buttons = driver.find_elements('class', 'action_button')
    for btn in buttons:
        label = btn.get_attribute('content-desc')
        assert label and len(label) > 0

def test_screenshot_prevention():
    driver.find_element('id', 'sensitive_screen').click()
    assert driver.get_window_size()['secure'] is True

def test_multi_tap_prevention():
    btn = driver.find_element('id', 'submit_order')
    for _ in range(5):
        btn.click()
    orders = get_order_count()
    assert orders == 1
